import { Client } from "my-provider-sdk";

export interface MyProviderEnv {
  MY_PROVIDER_API_KEY: string;
  MY_PROVIDER_REGION: string;
}

// Create the client per request from the Worker binding.
export function createMyProvider(env: MyProviderEnv) {
  return new Client({ apiKey: env.MY_PROVIDER_API_KEY, region: env.MY_PROVIDER_REGION });
}
